@namespace Lumeo
@implements IAsyncDisposable
@inject Lumeo.Services.IComponentInteropService Interop

@{
    var context = new TooltipContext(_isOpen, _wrapperId);
}

<div id="@_wrapperId" class="relative inline-flex"
     @onmouseenter="HandleMouseEnter"
     @onmouseleave="HandleMouseLeave"
     @onclick="HandleTap"
     @attributes="AdditionalAttributes">
    <CascadingValue Value="context" IsFixed="false">
        @ChildContent
    </CascadingValue>
</div>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public int ShowDelay { get; set; } = 200;
    [Parameter] public int HideDelay { get; set; } = 0;
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _wrapperId = LumeoIds.New("tooltip-wrapper");
    private bool _hovered;
    // rc.44 — on touch devices a tap "pins" the tooltip open until the next
    // tap elsewhere (registerClickOutside also now listens for touchstart, so
    // dismissal works equally on mobile).
    private bool _pinned;
    private bool _clickOutsideRegistered;
    private readonly DelayedDispatch _dispatch = new();

    private bool _isOpen => _hovered || _pinned;

    private void HandleMouseEnter()
    {
        _dispatch.Cancel();
        if (ShowDelay <= 0)
        {
            _hovered = true;
            StateHasChanged();
        }
        else
        {
            _dispatch.Schedule(ShowDelay, () => InvokeAsync(() =>
            {
                _hovered = true;
                StateHasChanged();
                return Task.CompletedTask;
            }));
        }
    }

    private void HandleMouseLeave()
    {
        _dispatch.Cancel();
        if (HideDelay <= 0)
        {
            _hovered = false;
            StateHasChanged();
        }
        else
        {
            _dispatch.Schedule(HideDelay, () => InvokeAsync(() =>
            {
                _hovered = false;
                StateHasChanged();
                return Task.CompletedTask;
            }));
        }
    }

    // Tap toggles the pinned state. The first tap on a touch device fires
    // both `mouseenter` (browser-emulated) and `click` — that's fine: pin
    // simply sticks open. A second tap on the trigger unpins.
    private async Task HandleTap()
    {
        _pinned = !_pinned;
        if (_pinned && !_clickOutsideRegistered)
        {
            await Interop.RegisterClickOutside(_wrapperId, null, OnClickOutside);
            _clickOutsideRegistered = true;
        }
        StateHasChanged();
    }

    private Task OnClickOutside()
    {
        if (_pinned)
        {
            _pinned = false;
            _hovered = false;
            StateHasChanged();
        }
        return Task.CompletedTask;
    }

    public async ValueTask DisposeAsync()
    {
        _dispatch.Dispose();
        if (_clickOutsideRegistered)
        {
            try { await Interop.UnregisterClickOutside(_wrapperId); }
            catch (Microsoft.JSInterop.JSDisconnectedException) { }
            _clickOutsideRegistered = false;
        }
    }

    public record TooltipContext(bool IsOpen, string WrapperId);
}

@namespace Lumeo
@implements IAsyncDisposable

@*  rc.45 — fixed-position rendering + collision flip.
    Previously the tooltip was an absolutely positioned child of the trigger
    wrapper, anchored with Tailwind classes (`bottom-full left-1/2 ...`).
    That meant a tooltip near the viewport edge clipped against it.
    We now mirror the Popover pattern: render with `position: fixed`, hand
    placement off to `ComponentInteropService.PositionFixed` (floating-ui
    under the hood), which auto-flips to the opposite side when collision
    space is tight. Side is still consumer-controlled as a preference. *@
@if (IsOpen)
{
    <div id="@_contentId" role="tooltip" class="@CssClass" @attributes="AdditionalAttributes">
        @ChildContent
        @if (ShowArrow)
        {
            <div class="@ArrowClasses"></div>
        }
    </div>
}

@inject Lumeo.Services.IComponentInteropService Interop

@code {
    [CascadingParameter] public Tooltip.TooltipContext? Context { get; set; }

    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public Lumeo.Side Side { get; set; } = Lumeo.Side.Top;
    [Parameter] public bool ShowArrow { get; set; } = true;
    [Parameter] public int Offset { get; set; } = 8;
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _contentId = LumeoIds.New("tooltip-content");
    private bool _registered;

    private bool IsOpen => Context?.IsOpen ?? false;

    private string CssClass => Cx.Join(
        "fixed z-50 overflow-visible rounded-md bg-primary px-3 py-1.5 text-xs text-primary-foreground",
        AnimationClasses,
        Class);

    private string AnimationClasses => IsOpen
        ? "opacity-100 visible animate-fade-in"
        : "opacity-0 invisible";

    private string SideStr => Side switch
    {
        Lumeo.Side.Top => "top",
        Lumeo.Side.Bottom => "bottom",
        Lumeo.Side.Left => "left",
        Lumeo.Side.Right => "right",
        _ => "top"
    };

    // Rotated square — same visual as Popover/HoverCard but no border (tooltip is a solid primary surface).
    private string ArrowClasses => Side switch
    {
        Lumeo.Side.Top => "absolute left-1/2 top-full -translate-x-1/2 -translate-y-1/2 rotate-45 h-2 w-2 bg-primary",
        Lumeo.Side.Bottom => "absolute left-1/2 bottom-full -translate-x-1/2 translate-y-1/2 rotate-45 h-2 w-2 bg-primary",
        Lumeo.Side.Left => "absolute top-1/2 left-full -translate-y-1/2 -translate-x-1/2 rotate-45 h-2 w-2 bg-primary",
        Lumeo.Side.Right => "absolute top-1/2 right-full -translate-y-1/2 translate-x-1/2 rotate-45 h-2 w-2 bg-primary",
        _ => "absolute left-1/2 top-full -translate-x-1/2 -translate-y-1/2 rotate-45 h-2 w-2 bg-primary"
    };

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (IsOpen && !_registered && Context is not null)
        {
            await Interop.PositionFixed(_contentId, Context.WrapperId, "center", false, SideStr);
            _registered = true;
        }
        else if (!IsOpen && _registered)
        {
            await Cleanup();
        }
    }

    private async Task Cleanup()
    {
        try { await Interop.UnpositionFixed(_contentId); }
        catch (Microsoft.JSInterop.JSDisconnectedException) { }
        _registered = false;
    }

    public async ValueTask DisposeAsync()
    {
        if (_registered) await Cleanup();
    }

}

@namespace Lumeo

<div class="@CssClass" @attributes="AdditionalAttributes">
    @ChildContent
</div>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => $"inline-flex {Class}".Trim();
}
